			}
			if (empty($mimetype)) {
				$mimetype = 'application/octet-stream';
			}
			if (!in_array($mimetype, ['image/jpeg', 'image/jpg', 'image/png', 'image/gif'])) {
				throw new \Exception("Uploaded file is not a valid image");
			}

