				'jpg',
				'png',
				'gif'
			])) {
				throw new Exception("Invalid file-extension, use one of: jpeg, jpg, png, gif");
			}

			// Move file
			if (!move_uploaded_file($_FILES[$fieldname]['tmp_name'], $path . $fielddata['image_name'] . '.' . $file_extension)) {
