            return false;
        }
    }

    if ($archive_file !== null) {
        try {
            $res = $zip->extractTo(UploadFile::realpath($zip_dir), $archive_file);
        } catch (ValueError $t) {
            if (file_exists($zip_archive)){
                LoggerManager::getLogger()->fatal(sprintf('ZIP Error(%d): Invalid file(%s). Deleting.', $res, $zip_archive));
                unlink($zip_archive);
            }
            throw $t;
        }

