function get_path_ext($path){
	$name = get_path_this($path);
	$ext = '';
	if(strstr($name,'.')){$ext = substr($name,strrpos($name,'.')+1);}
	$isMatch = preg_match("/[0-9a-zA-Z_]+/",$ext,$match);// 只允许数字字母和下划线
	return ($isMatch && $match[0]) ? strtolower($match[0]):'';
}

